/**
 * Extracts and parses JSON from a string, removing Markdown code blocks if present.
 * @param {string} llmOutput - The raw string returned by the LLM.
 * @returns {object} - The parsed JSON object.
 * @throws {Error} - If no JSON can be found or parsed.
 */
function parseLlmJson(llmOutput) {
  // 1. Regex to find content inside ```json ... ``` or just ``` ... ```
  //    Matches: ```(optional language) (content) ```
  const jsonCodeBlockRegex = /```(?:json)?\s*([\s\S]*?)\s*```/i;

  const match = llmOutput.match(jsonCodeBlockRegex);
  let jsonString = '';

  if (match && match[1]) {
    // We found a code block, use the content inside capture group 1
    jsonString = match[1];
  } else {
    // 2. Fallback: If no code block found, try to extract from first '{' to last '}'
    // This handles cases where the LLM just returns raw JSON or text mixed with JSON without markdown.
    const firstBrace = llmOutput.indexOf('{');
    const lastBrace = llmOutput.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1) {
      jsonString = llmOutput.substring(firstBrace, lastBrace + 1);
    } else {
      throw new Error("No JSON structure found in input string.");
    }
  }

  // 3. Parse the extracted string
  try {
    return JSON.parse(jsonString);
  } catch (error) {
    console.error("Extraction successful, but JSON.parse failed on:", jsonString);
    throw new Error(`Invalid JSON content: ${error.message}`);
  }
}


// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.parsedContentObject = parseLlmJson(item.json.candidates[0].content.parts[0].text);
}

return $input.all();

