// Fetch the resolved search results from the parallel branch
const searchResults = $('Resolve URLs (Impact Search)').first().json.search_results;

// Helper to generate precise W3C Text Fragments
function buildTextFragment(text) {
    if (!text) return "";
    const words = text.trim().split(/\s+/);
    const startText = words.slice(0, 5).join(' ');
    let fragment = encodeURIComponent(startText).replace(/-/g, '%2D');

    if (words.length > 8) {
        const endText = words.slice(-3).join(' ');
        fragment += ',' + encodeURIComponent(endText).replace(/-/g, '%2D');
    }
    return `#:~:text=${fragment}`;
}

// Resolve the indices for all items in the batch
for (const item of $input.all()) {
    const data = item.json.parsedContentObject;
    if (!data) continue;

    const resolveItem = (obj) => {
        if (obj.source_document === 'web' && obj.search_result_index) {
            const snippet = searchResults[obj.search_result_index];
            if (snippet) {
                // Inject actual text and build the fragment URL
                obj.source_url = snippet.url + buildTextFragment(snippet.original_text);

                if (obj.hasOwnProperty('evidence_quote')) {
                    obj.evidence_quote = snippet.original_text;
                } else if (obj.hasOwnProperty('source_quote')) {
                    obj.source_quote = snippet.original_text;
                }
            }
        }
    };

    if (data.metrics) data.metrics.forEach(resolveItem);
    if (data.significant_events) data.significant_events.forEach(resolveItem);
}

return $input.all();
